var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"어라……?","JPN":"あれ……？","ENG":"Huh...?","TWN":"咦"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"여기는 우주잖아…? 어째서 갑자기 우주에……?","JPN":"ここって宇宙……？　どうしていきなり宇宙に……？","ENG":"I'm in space...? How did I end up here all of a sudden...?","TWN":"這裡是宇宙嗎？為什麼？突在宇宙？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"마침내 모든 분기점의 조건을 만족하고, 최초의 기억에 도달했군요.","JPN":"ついに全ての分岐点の条件を満たし、最初の記憶にたどり着きましたね。","ENG":"Alas. All conditions for the turning point have been fulfilled. You've reached the origin of your memory.","TWN":"終於滿足了所有分支點的條件，達到了最初的記憶。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"세피로트 나무의 파편.","JPN":"セフィロトの破片。","ENG":"Fragment of the Tree of Sephiroth.","TWN":"生命樹的碎片。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"분기점이라고요……?","JPN":"分岐点……？","ENG":"Turning point...?","TWN":"分岔？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"당신은 누구죠? 여긴 어디인가요?","JPN":"あなたは誰？　ここはどこですか？","ENG":"Who are you? And where am I?","TWN":"你是誰啊？這裡是哪裡？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"이곳은 달의 뒷면, 섹터-32. 잠정적 세피라 포인트.","JPN":"ここは月の裏側、セクター32。暫定的セフィラポイント。","ENG":"This is the dark side of the moon. Sector-32. A provisional Sephira Point.","TWN":"這裡是月球背面，第32區。暫定的生命樹點。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"세피로트 나무의 파편인 당신이 처음으로 발견된 곳이죠.","JPN":"セフィロトの破片であるあなたが、初めて発見された場所です。","ENG":"It is also where you, Fragment of the Tree of Sephiroth, were first discovered.","TWN":"這裡是作為生命樹碎片的你首次被發現的地方。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"제가 처음으로 발견된 곳이라고요?","JPN":"私が初めて発見された場所？","ENG":"This is where I was discovered?","TWN":"是我被第一次發現的地方嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그렇습니다, 파편.","JPN":"そうです、破片。","ENG":"Correct, Fragment.","TWN":"是的，碎片。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"분기점의 조건은 늑대가 당신을 찾는 것. 그리고 늑대와 당신이 접촉하는 것.","JPN":"分岐点の条件はオオカミがあなたを見つけること。そしてオオカミとあなたが接触すること。","ENG":"The conditions were that the Wolf finds you and the two of you make contact.","TWN":"分岔點的條件是狼找到你。然後是狼和你接觸。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그리고 당신이 스스로의 힘을 자각한 채로 바즈라와 접촉하는 것.","JPN":"そしてあなたが自らの力を自覚した状態で、ヴァジュラと接触することです。","ENG":"And you awaken your power and make contact with vajra.","TWN":"然後你在意識到自己力量的情況下與金剛杵接觸。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"모든 조건을 만족한 지금, 우리는 바즈라라는 연결 고리를 통해 20년이라는 시간을 초월하여.","JPN":"全ての条件を満たした今、私たちはヴァジュラという繋がりによって、20年という時間を超え、","ENG":"Now that all conditions are met, we're able to transcend twenty years of time, through the link that is vajra.","TWN":"滿足所有條件的現在，我們通過名為金剛杵的連接環節，跨越了20年的時間。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"인과 연산을 통해, 대화를 나눌 수 있게 된 겁니다.","JPN":"因果演算を通して、会話できるようになったのです。","ENG":"Using causality calculation, this conversation is now possible.","TWN":"通過因果運算，我們可以進行對話了。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"시간을… 초월한다고요……?","JPN":"時間を……超える……？","ENG":"Transcend... time...?","TWN":"時間……超越嗎？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"자, 잠깐! 이 바즈라는 천사님이 준 거예요!","JPN":"ま、待ってください！　このヴァジュラは天使様からもらったものです！","ENG":"Wait a minute! This vajra was a gift from the angel!","TWN":"等、等等！這個金剛杵是天使給的！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그 바즈라는 연합의 물건입니다. 지금은 주인을 잃어버린 자율 수행 병기 중에 하나죠.","JPN":"そのヴァジュラは連合のものです。今は主を失った、自律遂行兵器のうちのひとつです。","ENG":"That vajra belongs to the Alliance. It is one of the autonomous weapons that lost its master.","TWN":"那個金剛杵是聯盟的物品。現在是失去主人的自主執行兵器之一。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"그리고 현 시점으로부터 20년 뒤, 저는 당신이 지상에 강림할 때, 바즈라를 넘겨주게 됩니다.","JPN":"そして現時点より20年後、私はあなたが地上に降臨する際、ヴァジュラを渡すことになります。","ENG":"And twenty years from now, I'll hand it to you when you descend to Earth.","TWN":"而在現時點的20年後，我會在你降臨地面時，將金剛杵交給你。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"당신을 지키는 동시에 이 순간을 위한 소통의 매개체로서 말이죠.","JPN":"あなたを守ると同時に、この瞬間のための連絡媒体として。","ENG":"To protect you and to serve as a medium for this moment.","TWN":"在保護你的同時，也作為這一刻溝通的媒介。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그, 그렇지만…! 당신은 꿈속에서 봤던 천사님과는 조금 다른 걸요……?","JPN":"で、でも……！　あなたは夢の中に出てきた天使様とは、ちょっと違いますよ……？","ENG":"B-but...! You're not quite the angel I saw in my dreams...","TWN":"但，但是！你和我夢中見到的天使有點不一樣？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"현 시점에서 파편인 당신은 아직 자아가 형성되지 않은 상태입니다.","JPN":"現時点で破片のあなたは、まだ自我が形成されていない状態です。","ENG":"At this point in time, you're still a fragment. Your ego hasn't fully formed yet.","TWN":"在目前的情況下，作為碎片的你尚未形成自我意識。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_QM","text":{"KOREA":"아마도 당신이 저를 천사라고 생각했던 건, 당신이 모방한 인간의 무의식이 반영된 것이겠죠.","JPN":"おそらくあなたが私を天使だと思ったのは、あなたが模倣した人間の無意識が反映された結果でしょう。","ENG":"What you saw was likely a projection of the unconscious mind you mimicked from humanity.","TWN":"也許你認為我是天使，是因為你模仿的人類潛意識的反映吧。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"마, 맙소사……!","JPN":"そ、そんな……！","ENG":"N-no way...!","TWN":"天，天哪！"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면 천사님… 당신은 대체 누구죠……?","JPN":"だったら天使様……あなたはいったい……？","ENG":"Then who are you... really, angel...?","TWN":"那麼，天使……你到底是誰？"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ASIMOV_QLIPHOTH_NPC_NULL","text":{"KOREA":"저는 성간 관리 연합의 총괄 네비게이션 시스템, 아시모프.","JPN":"私は星間管理連合の総括ナビゲーションシステム、アシモフ。","ENG":"I am Asimov, the Interstellar Administration Alliance Central Navigation System.","TWN":"我是星際管理聯合的總導航系統，阿西莫夫。"},"stage":{"bg":"COUNTERSIDE_AURORA_02","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};